    example: { title: "Transcriptie van een matrijsstreng", prompt: "Maak van 3′-TAC CGA AAA ATT-5′ het mRNA-fragment.", steps: ["Herken dat dit een DNA-matrijsstreng is.", "Gebruik de transcriptieregels: T -> A, A -> U, C -> G en G -> C.", "Schrijf per triplet: TAC -> AUG, CGA -> GCU, AAA -> UUU en ATT -> UAA.", "Noteer het mRNA als 5′-AUG GCU UUU UAA-3′."] },
    extraExamples: [{
        title: "Transcriptie met vaste omzetregels",
        prompt: "Gebruik het schema om te laten zien waarom transcriptie een overschrijving naar mRNA is en geen kopie met dezelfde letters.",
        visual: { type: "diagram", component: "DnaExpressionDiagram", variant: "transcription", alt: "Schema van transcriptie met DNA-matrijs en mRNA-product.", caption: "Schema: transcriptie maakt complementair mRNA met U in plaats van T.", purpose: "explanation-only" },
        figureExplanation: {
          observation: "Je ziet een DNA-matrijsstreng, een pijl voor transcriptie en daaronder een complementair mRNA-fragment.",
          meaning: "Het mRNA krijgt dus niet dezelfde letters als de matrijsstreng. Je gebruikt transcriptieregels en noteert RNA met U.",
          conclusion: "Transcriptie levert een complementair mRNA-product op dat later bij translatie gebruikt wordt.",
          examUse: "Schrijf bij de uitwerking eerst op welke streng gegeven is en laat daarna per base of per triplet zien hoe je naar mRNA gaat.",
          commonMistake: "Veelgemaakte fout: T in mRNA laten staan of een coderende streng behandelen alsof het altijd de matrijsstreng is.",
        },
        steps: ["Herken of je naar een matrijsstreng kijkt.", "Gebruik RNA-paringsregels: A-U, T-A, C-G, G-C.", "Controleer aan het eind dat in mRNA geen T meer staat."],
        conclusion: "De figuur dwingt je de omzetting gecontroleerd te doen in plaats van letters blind over te schrijven.",
      }],
    examApproach: ["Bepaal eerst of je DNA of mRNA ziet.", "Controleer of het om een matrijsstreng of coderende streng gaat.", "Maak daarna pas het mRNA met U en zonder T.", "Noteer de richting als de opgave die geeft."],
    examAnswer: "Transcriptie maakt uit een DNA-stuk een complementair mRNA-fragment. Gebruik je een DNA-matrijsstreng, dan schrijf je complementair over met RNA-basen: A in DNA geeft U in RNA, T geeft A, C geeft G en G geeft C. Let ook op het verschil tussen matrijsstreng en coderende streng en op de 3′/5′-richting als die is gegeven.",
    commonMistakes: ["T in mRNA laten staan", "een coderende streng behandelen alsof het altijd de matrijsstreng is", "letters alleen kopiëren zonder complementaire omzetting"],
    memoryAnchor: ["Transcriptie = DNA -> mRNA.", "RNA heeft U, geen T.", "Eerst bepalen welke DNA-streng je hebt."],
    miniCheck: [{ question: "Wat is het product van transcriptie?", answer: "mRNA." }, { question: "Welke RNA-base hoort tegenover DNA-A?", answer: "U." }, { question: "Waarop moet je letten als 3′ en 5′ zijn gegeven?", answer: "Op de leesrichting van streng en product." }],
