    example: { title: "Volledige route", prompt: "Gegeven: DNA-matrijsstreng 3′-TAC CGA AAA ATT-5′. Bepaal de aminozuurketen.", steps: ["Herken de streng als DNA-matrijsstreng.", "Maak het mRNA: 5′-AUG GCU UUU UAA-3′.", "Deel op in codons: AUG, GCU, UUU, UAA.", "Zoek in BINAS de mRNA-codons op: Met, Ala, Phe, stop.", "Schrijf als eindantwoord: Met-Ala-Phe; de keten stopt bij UAA."] },
