    miniCheck: [{ question: "Wat doet overshoot?", answer: "Te groot verbruik en vaak te hoge berekende analyte." }, { question: "Waarom is erlenmeyerwater meestal oké?", answer: "Het verandert mol monster niet." }, { question: "Wat doet een verdwijnende luchtbel?", answer: "Afgelezen verbruik wordt te groot." }],
